403	always @(posedge clock) begin
404	    if (reset) begin
405	        status_code <= E_OK;
406	        state <= S_WAIT_POWER_TRIGGER;
407	        old_state <= 0;
408	
409	        sync_short_reset <= 0;
410	
411	        sync_long_reset <= 0;
412	        sync_long_enable <= 0;
413	
414	        byte_count <= 0;
415	
416	        pkt_begin <= 0;
417	        pkt_ht <= 0;
418	
419	
420	        rot_eq_count <= 0;
421	        normal_eq_count <= 0;
422	        abs_eq_i <= 0;
423	        abs_eq_q <= 0;
424	
425	        do_descramble <= 0;
426	        num_bits_to_decode <= 0;
427	        short_gi <= 0;
428	        pkt_rate <= 0;
429	
430	        equalizer_reset <= 0;
431	        equalizer_enable <= 0;
432	        ht_next <= 0;
433	
434	        pkt_len <= 0;
435	
436	        ofdm_reset <= 0;
437	        ofdm_enable <= 0;
438	        ofdm_in_stb <= 0;
439	        ofdm_in_i <= 0;
440	        ofdm_in_q <= 0;
441	
442	        sample_count <= 0;
443	
444	        sync_long_out_count <= 0;
445	
446	        signal_bits <= 0;
447	        legacy_sig_stb <= 0;
448	
449	        ht_sig1 <= 0;
450	        ht_sig2 <= 0;
451	        crc_in_stb <= 0;
452	        crc_in <= 0;
453	        crc_count <= 0;
454	        crc_reset <= 0;
455	        ht_sig_crc_ok <= 0;
456	        ht_sig_stb <= 0;
457	
458	        fcs_out_strobe <= 0;
459	        fcs_ok <= 0;
460	    end else if (enable) begin
461	        old_state <= state;
462	
463	        case(state)
464	            S_WAIT_POWER_TRIGGER: begin
465	                sync_long_enable <= 0;
466	                equalizer_enable <= 0;
467	                ofdm_enable <= 0;
468	
469	                if (power_trigger) begin
470	                    `ifdef DEBUG_PRINT
471	                        $display("Power triggered.");
472	                    `endif
473	                    sync_short_reset <= 1;
474	                    state <= S_SYNC_SHORT;
475	                end
476	            end
477	
478	            S_SYNC_SHORT: begin
479	                if (sync_short_reset) begin
480	                    sync_short_reset <= 0;
481	                end
482	
483	                if (~power_trigger) begin
484	                    // power level drops before finding STS
485	                    state <= S_WAIT_POWER_TRIGGER;
486	                end
487	
488	                if (short_preamble_detected) begin
489	                    `ifdef DEBUG_PRINT
490	                        $display("Short preamble detected");
491	                    `endif
492	                    sync_long_reset <= 1;
493	                    sync_long_enable <= 1;
494	                    sample_count <= 0;
495	                    state <= S_SYNC_LONG;
496	                end
497	                
498	            end
499	
500	            S_SYNC_LONG: begin
501	                if (sync_long_reset) begin
502	                    sync_long_reset <= 0;
503	                end
504	
505	                if (sample_in_strobe) begin
506	                    sample_count <= sample_count + 1;
507	                end
508	                if (sample_count > 320) begin
509	                    state <= S_WAIT_POWER_TRIGGER;
510	                end
511	
512	                if (~power_trigger) begin
513	                    state <= S_WAIT_POWER_TRIGGER;
514	                end
515	
516	                if (long_preamble_detected) begin
517	                    pkt_rate <= {1'b0, 3'b0, 4'b1011};
518	                    do_descramble <= 0;
519	                    num_bits_to_decode <= 48;
520	
521	                    ofdm_reset <= 1;
522	                    ofdm_enable <= 1;
523	
524	                    equalizer_enable <= 1;
525	                    equalizer_reset <= 1;
526	
527	                    byte_count <= 0;
528	                    state <= S_DECODE_SIGNAL;
529	                end
530	            end
531	
532	            S_DECODE_SIGNAL: begin
533	                if (ofdm_reset) begin
534	                    ofdm_reset <= 0;
535	                end
536	
537	                if (equalizer_reset) begin
538	                    equalizer_reset <= 0;
539	                end
540	
541	                ofdm_in_stb <= equalizer_out_strobe;
542	                ofdm_in_i <= eq_out_i;
543	                ofdm_in_q <= eq_out_q;
544	
545	                if (byte_out_strobe) begin
546	                    signal_bits <= {byte_out, signal_bits[23:8]};
547	                    byte_count <= byte_count + 1;
548	                end
549	
550	                if (byte_count == 3) begin
551	                    byte_count <= 0;
552	                    `ifdef DEBUG_PRINT
553	                        $display("[SIGNAL] rate = %04b, ", legacy_rate,
554	                            "length = %012b (%d), ", legacy_len, legacy_len,
555	                            "parity = %b, ", legacy_sig_parity,
556	                            "tail = %6b", legacy_sig_tail);
557	                    `endif
558	                    ofdm_reset <= 1;
559	                    state <= S_CHECK_SIGNAL;
560	                end
561	            end
562	
563	            S_CHECK_SIGNAL: begin
564	                if (ofdm_reset) begin
565	                    ofdm_reset <= 0;
566	                end
567	
568	                if (~legacy_sig_parity_ok) begin
569	                    status_code <= E_PARITY_FAIL;
570	                    state <= S_SIGNAL_ERROR;
571	                end else if (legacy_sig_rsvd) begin
572	                    status_code <= E_WRONG_RSVD;
573	                    state <= S_SIGNAL_ERROR;
574	                end else if (|legacy_sig_tail) begin
575	                    status_code <= E_WRONG_TAIL;
576	                    state <= S_SIGNAL_ERROR;
577	                end else begin
578	                    legacy_sig_stb <= 1;
579	                    status_code <= E_OK;
580	                    if (legacy_rate == 4'b1011) begin
581	                        abs_eq_i <= 0;
582	                        abs_eq_q <= 0;
583	                        rot_eq_count <= 0;
584	                        normal_eq_count <= 0;
585	                        state <= S_DETECT_HT;
586	                    end else begin
587	                        pkt_rate <= {1'b0, 3'b0, legacy_rate};
588	                        num_bits_to_decode <= (legacy_len+3)<<4;
589	                        do_descramble <= 1;
590	                        ofdm_reset <= 1;
591	                        byte_count <= 0;
592	                        pkt_len <= legacy_len;
593	                        byte_count <= 0;
594	                        pkt_begin <= 1;
595	                        pkt_ht <= 0;
596	                        state <= S_DECODE_DATA;
597	                    end
598	                end
599	            end
600	
601	            S_SIGNAL_ERROR: begin
602	                state <= S_WAIT_POWER_TRIGGER;
603	            end
604	
605	            S_DETECT_HT: begin
606	                legacy_sig_stb <= 0;
607	
608	                if (equalizer_out_strobe) begin
609	                    abs_eq_i <= eq_out_i[15]? ~eq_out_i+1: eq_out_i;
610	                    abs_eq_q <= eq_out_q[15]? ~eq_out_q+1: eq_out_q;
611	                    if (abs_eq_q > abs_eq_i) begin
612	                        rot_eq_count <= rot_eq_count + 1;
613	                    end else begin
614	                        normal_eq_count <= normal_eq_count + 1;
615	                    end
616	                end
617	
618	                if (rot_eq_count >= 4) begin
619	                    // HT-SIG detected
620	                    byte_count <= 0;
621	                    pkt_rate <= {1'b0, 3'b0, 4'b1011};
622	                    num_bits_to_decode <= 96;
623	                    do_descramble <= 0;
624	                    ofdm_reset <= 1;
625	                    state <= S_HT_SIGNAL;
626	                end else if (normal_eq_count > 4) begin
627	                    pkt_len <= legacy_len;
628	                    num_bits_to_decode <= (legacy_len+3)<<4;
629	                    do_descramble <= 1;
630	                    ofdm_reset <= 1;
631	                    byte_count <= 0;
632	                    pkt_begin <= 1;
633	                    pkt_ht <= 0;
634	                    state <= S_DECODE_DATA;
635	                end
636	            end
637	
638	            S_HT_SIGNAL: begin
639	                if (ofdm_reset) begin
640	                    ofdm_reset <= 0;
641	                end
642	
643	                ofdm_in_stb <= eq_out_stb_delayed;
644	                // rotate clockwise by 90 degree
645	                ofdm_in_i <= eq_out_q_delayed;
646	                ofdm_in_q <= ~eq_out_i_delayed+1;
647	
648	                if (byte_out_strobe) begin
649	                    if (byte_count < 3) begin
650	                        ht_sig1 <= {byte_out, ht_sig1[23:8]};
651	                    end else begin
652	                        ht_sig2 <= {byte_out, ht_sig2[23:8]};
653	                    end
654	                    byte_count <= byte_count + 1;
655	                end
656	
657	                if (byte_count == 6) begin
658	                    byte_count <= 0;
659	                    `ifdef DEBUG_PRINT
660	                        $display("[HT SIGNAL] mcs = %07b (%d), ", ht_mcs, ht_mcs,
661	                            "CBW: %d, ", ht_cbw? 40: 20,
662	                            "length = %012b (%d), ", ht_len, ht_len,
663	                            "rsvd = %d, ", ht_rsvd,
664	                            "aggr = %d, ", ht_aggregation,
665	                            "stbd = %02b, ", ht_stbc,
666	                            "fec = %d, ", ht_fec_coding,
667	                            "sgi = %d, ", ht_sgi,
668	                            "num_ext = %d, ", ht_num_ext,
669	                            "crc = %08b, ", crc,
670	                            "tail = %06b", ht_sig_tail);
671	                    `endif
672	                    crc_count <= 0;
673	                    crc_reset <= 1;
674	                    crc_in_stb <= 0;
675	                    ht_sig_crc_ok <= 0;
676	                    state <= S_CHECK_HT_SIG_CRC;
677	                end
678	            end
679	
680	            S_CHECK_HT_SIG_CRC: begin
681	                crc_reset <= 0;
682	                crc_count <= crc_count + 1;
683	
684	                if (crc_count < 24) begin
685	                    crc_in_stb <= 1;
686	                    crc_in <= ht_sig1[crc_count];
687	                end else if (crc_count < 34) begin
688	                    crc_in_stb <= 1;
689	                    crc_in <= ht_sig2[crc_count-24];
690	                end else if (crc_count == 34) begin
691	                    crc_in_stb <= 0;
692	                end else if (crc_count == 35) begin
693	                    if (crc_out ^ crc) begin
694	                        status_code <= E_WRONG_CRC;
695	                        ht_sig_stb <= 1;
696	                        state <= S_HT_SIG_ERROR;
697	                    end else begin
698	                        `ifdef DEBUG_PRINT
699	                            $display("[HT SIGNAL] CRC OK");
700	                        `endif
701	                        ht_sig_crc_ok <= 1;
702	                        ht_sig_stb <= 1;
703	                        ofdm_reset <= 1;
704	                        state <= S_CHECK_HT_SIG;
705	                    end
706	                end
707	            end
708	
709	            S_CHECK_HT_SIG: begin
710	                ofdm_reset <= 0;
711	                ht_sig_stb <= 0;
712	                if (ht_mcs > 7) begin
713	                    status_code <= E_UNSUPPORTED_MCS;
714	                    state <= S_HT_SIG_ERROR;
715	                end else if (ht_cbw) begin
716	                    status_code <= E_UNSUPPORTED_CBW;
717	                    state <= S_HT_SIG_ERROR;
718	                end else if (ht_rsvd == 0) begin
719	                    status_code <= E_HT_WRONG_RSVD;
720	                    state <= S_HT_SIG_ERROR;
721	                end else if (ht_stbc != 0) begin
722	                    status_code <= E_UNSUPPORTED_STBC;
723	                    state <= S_HT_SIG_ERROR;
724	                end else if (ht_fec_coding) begin
725	                    status_code <= E_UNSUPPORTED_FEC;
726	                    state <= S_HT_SIG_ERROR;
727	                end else if (short_gi) begin
728	                    status_code <= E_UNSUPPORTED_SGI;
729	                    state <= S_HT_SIG_ERROR;
730	                end else if (ht_num_ext != 0) begin
731	                    status_code <= E_UNSUPPORTED_SPATIAL;
732	                    state <= S_HT_SIG_ERROR;
733	                end else if (ht_sig_tail != 0) begin
734	                    status_code <= E_HT_WRONG_TAIL;
735	                    state <= S_HT_SIG_ERROR;
736	                end else begin
737	                    sync_long_out_count <= 0;
738	                    state <= S_HT_STS;
739	                end
740	            end
741	
742	            S_HT_SIG_ERROR: begin
743	                ht_sig_stb <= 0;
744	                state <= S_WAIT_POWER_TRIGGER;
745	            end
746	
747	            S_HT_STS: begin
748	                if (sync_long_out_strobe) begin
749	                    sync_long_out_count <= sync_long_out_count + 1;
750	                end
751	                if (sync_long_out_count == 64) begin
752	                    sync_long_out_count <= 0;
753	                    ht_next <= 1;
754	                    state <= S_HT_LTS;
755	                end
756	            end
757	
758	            S_HT_LTS: begin
759	                short_gi <= ht_sgi;
760	                if (sync_long_out_strobe) begin
761	                    sync_long_out_count <= sync_long_out_count + 1;
762	                end
763	                if (sync_long_out_count == 64) begin
764	                    ht_next <= 0;
765	                    num_bits_to_decode <= (ht_len+3)<<4;
766	                    pkt_rate <= {1'b1, ht_mcs};
767	                    do_descramble <= 1;
768	                    ofdm_reset <= 1;
769	                    byte_count <= 0;
770	                    pkt_len <= ht_len;
771	                    pkt_begin <= 1;
772	                    pkt_ht <= 1;
773	                    state <= S_DECODE_DATA;
774	                end
775	            end
776	
777	            S_DECODE_DATA: begin
778	                pkt_begin <= 0;
779	                legacy_sig_stb <= 0;
780	
781	                if (ofdm_reset) begin
782	                    ofdm_reset <= 0;
783	                end
784	
785	                ofdm_in_stb <= eq_out_stb_delayed;
786	                ofdm_in_i <= eq_out_i_delayed;
787	                ofdm_in_q <= eq_out_q_delayed;
788	
789	                if (byte_out_strobe) begin
790	                    `ifdef DEBUG_PRINT
791	                        $display("[BYTE] [%4d / %-4d] %02x", byte_count+1, pkt_len,
792	                            byte_out);
793	                    `endif
794	                    byte_count <= byte_count + 1;
795	                end
796	
797	                if (byte_count >= pkt_len) begin
798	                    fcs_out_strobe <= 1;
799	                    if (pkt_fcs == EXPECTED_FCS) begin
800	                        fcs_ok <= 1;
801	                        status_code <= E_OK;
802	                    end else begin
803	                        fcs_ok <= 0;
804	                        status_code <= E_WRONG_FCS;
805	                    end
806	                    state <= S_DECODE_DONE;
807	                end
808	            end
809	
810	            S_DECODE_DONE: begin
811	                `ifdef DEBUG_PRINT
812	                    $display("===== PACKET DECODE DONE =====");
813	                    if (status_code == E_OK) begin
814	                        $display("FCS CORRECT");
815	                    end else begin
816	                        $display("FCS WRONG");
817	                    end
818	                `endif
819	                fcs_out_strobe <= 0;
820	                state <= S_WAIT_POWER_TRIGGER;
821	            end
822	
823	            default: begin
824	                state <= S_WAIT_POWER_TRIGGER;
825	            end
826	        endcase
827	    end
828	end
829	
830	endmodule
