201	reg [15:0] num_sample;
202	reg [15:0] num_ofdm_symbol;
203	
204	integer i;
205	integer j;
206	always @(posedge clock) begin
207	    if (reset) begin
208	        for (j = 0; j < 16; j= j+1) begin
209	            cross_corr_buf[j] <= 0;
210	        end
211	        do_clear();
212	        state <= S_SKIPPING;
213	    end else if (enable) begin
214	        if (sample_in_strobe && state != S_SKIPPING) begin
215	            in_waddr <= in_waddr + 1;
216	            num_input_produced <= num_input_produced + 1;
217	        end
218	        num_input_avail <= num_input_produced - num_input_consumed;
219	
220	        case(state)
221	            S_SKIPPING: begin
222	                // skip the tail of  short preamble
223	                if (num_sample >= NUM_STS_TAIL) begin
224	                    num_sample <= 0;
225	                    state <= S_WAIT_FOR_FIRST_PEAK;
