249	            S_WAIT_FOR_SECOND_PEAK: begin
250	                do_mult();
251	
252	                if (metric_stb && (metric > metric_max2)) begin
253	                    metric_max2 <= metric;
254	                    addr2 <= in_raddr - 1;
255	                end
256	                gap <= addr2 - addr1;
