271	                        num_input_consumed <= addr1 - 16;
272	                        in_offset <= 0;
273	                        num_ofdm_symbol <= 0;
274	                        phase_correction <= 0;
275	                        next_phase_correction <= phase_offset;
276	                        state <= S_FFT;
