293	                if (~fft_loading && num_input_avail > 64) begin
294	                    fft_start <= 1;
295	                    in_offset <= 0;
296	                end
297	
298	                if (fft_start) begin
299	                    fft_start <= 0;
300	                    fft_loading <= 1;
301	                end
302	
303	                raw_stb <= fft_start | fft_loading;
304	                if (raw_stb) begin
305	                    if (phase_offset > 0) begin
306	                        if (next_phase_correction > PI) begin
307	                            phase_correction <= next_phase_correction - DOUBLE_PI;
308	                            next_phase_correction <= next_phase_correction + phase_offset - DOUBLE_PI;
309	                        end else begin
310	                            phase_correction <= next_phase_correction;
311	                            next_phase_correction <= next_phase_correction + phase_offset;
312	                        end
313	                    end else begin
314	                        if (next_phase_correction < -PI) begin
315	                            phase_correction <= next_phase_correction + DOUBLE_PI;
316	                            phase_correction <= next_phase_correction + DOUBLE_PI + phase_offset;
317	                        end else begin
318	                            phase_correction <= next_phase_correction;
319	                            phase_correction <= next_phase_correction + phase_offset;
320	                        end
321	                    end
322	                end
323	
324	                if (fft_start | fft_loading) begin
325	                    in_offset <= in_offset + 1;
326	
327	                    if (in_offset == 63) begin
328	                        fft_loading <= 0;
329	                        num_ofdm_symbol <= num_ofdm_symbol + 1;
330	                        if (num_ofdm_symbol > 0) begin
331	                            // skip the Guard Interval for data symbols
332	                            in_raddr <= in_raddr + gi_skip;
