387	
388	        mult_strobe <= 1;
389	        mult_stage <= 1;
390	    end
391	
392	    if (mult_stage == 1) begin
393	        stage_X0 <= cross_corr_buf[4];
394	        stage_X1 <= cross_corr_buf[5];
395	        stage_X2 <= cross_corr_buf[6];
396	        stage_X3 <= cross_corr_buf[7];
397	
