79	reg [3:0] pilot_count;
80	
81	reg signed [15:0] input_i;
82	reg signed [15:0] input_q;
83	
84	reg current_sign;
85	
86	wire signed [15:0] new_lts_i;
87	wire signed [15:0] new_lts_q;
88	wire new_lts_stb;
89	
90	reg calc_mean_strobe;
91	
92	reg [5:0] lts_waddr;
93	reg [6:0] lts_raddr; // one bit wider to detect overflow
94	reg [15:0] lts_i_in;
95	reg [15:0] lts_q_in;
96	reg lts_in_stb;
97	wire signed [15:0] lts_i_out;
98	wire signed [15:0] lts_q_out;
99	wire signed [15:0] lts_q_out_neg = ~lts_q_out + 1;
100	
101	reg [5:0] in_waddr;
