193	);
194	
195	complex_mult pilot_inst (
196	    .clock(clock),
197	    .enable(enable),
198	    .reset(reset),
199	    .a_i(input_i),
200	    .a_q(input_q),
201	    .b_i(lts_i_out),
202	    .b_q(lts_q_out),
